  const [tempContent, setTempContent] = useState(state.content);
  const [showToast, setShowToast] = useState(false);

  const handleLogout = () => {
    onLogout();
    window.location.hash = RoutePath.HOME;
  };

  const handleSaveContent = () => {
    onUpdate({ content: tempContent });
    setShowToast(true);
    setTimeout(() => setShowToast(false), 3000);
  };

  const addService = () => {
    const newService: Service = {
      id: Date.now().toString(),
      title: 'New Service',
      description: 'Service description goes here.',
      icon: 'Cpu',
      category: 'it'
    };
    onUpdate({ services: [...state.services, newService] });
  };

  const updateService = (id: string, updates: Partial<Service>) => {
    onUpdate({
      services: state.services.map(s => s.id === id ? { ...s, ...updates } : s)
    });
  };

  const deleteService = (id: string) => {
    onUpdate({ services: state.services.filter(s => s.id !== id) });
  };

  return (
    <div className="min-h-screen bg-slate-50 flex">
      {/* Sidebar */}
      <aside className="w-64 bg-slate-900 text-white flex flex-col shrink-0">
        <div className="p-8 border-b border-slate-800">
          <h2 className="text-xl font-bold flex items-center gap-2">
            <Settings className="text-blue-500" /> STATVION CMS
          </h2>
        </div>

        <nav className="flex-grow p-6 space-y-2">
          <button 
            onClick={() => setActiveTab('content')}
            className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl transition-all ${activeTab === 'content' ? 'bg-blue-600' : 'hover:bg-slate-800'}`}
          >
            <FileText size={20} /> Page Content
          </button>
          <button 
            onClick={() => setActiveTab('services')}
            className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl transition-all ${activeTab === 'services' ? 'bg-blue-600' : 'hover:bg-slate-800'}`}
          >
            <LayoutDashboard size={20} /> Services
          </button>
          <button 
            onClick={() => setActiveTab('seo')}
            className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl transition-all ${activeTab === 'seo' ? 'bg-blue-600' : 'hover:bg-slate-800'}`}
          >
            <Search size={20} /> SEO Settings
