          <div className="flex gap-4">
            <a href={`#${RoutePath.HOME}`} target="_blank" className="flex items-center gap-2 px-6 py-2 bg-slate-200 text-slate-700 font-bold rounded-lg hover:bg-slate-300">
              <Monitor size={18} /> Preview
