        </div>

        {activeTab === 'content' && (
          <div className="space-y-8 bg-white p-8 rounded-2xl shadow-sm border border-slate-200">
            <div>
              <label className="block text-sm font-bold text-slate-700 mb-2">Hero Title</label>
