              </div>
              <button className="bg-blue-600 text-white px-8 py-3 rounded-xl font-bold">Update SEO</button>
            </div>
          </div>
        )}

        {/* Toast */}
        {showToast && (
          <div className="fixed bottom-10 right-10 bg-slate-900 text-white px-8 py-4 rounded-xl shadow-2xl flex items-center gap-3 animate-bounce">
            <Check className="text-green-400" /> Changes Saved Successfully!
          </div>
        )}
      </main>
    </div>
  );
};

export default AdminDashboard;

