      icon: 'Cpu',
      category: 'it'
    };
    onUpdate({ services: [...state.services, newService] });
  };

  const updateService = (id: string, updates: Partial<Service>) => {
    onUpdate({
      services: state.services.map(s => s.id === id ? { ...s, ...updates } : s)
    });
  };

